@Test
public void testEqualsNullAndDifferentClass() {
    String html = "<div><p>Test</p></div>";
    Document doc = Jsoup.parse(html);
    Element el = doc.select("p").first();

    assertFalse(el.equals(null));
    assertFalse(el.equals("not an element"));
}

@Test
public void testEqualsSameReference() {
    String html = "<p class=\"test\">Content</p>";
    Document doc = Jsoup.parse(html);
    Element el = doc.select("p").first();

    assertTrue(el.equals(el));
}

@Test
public void testEqualsDifferentAttributes() {
    String html = "<div><p id=\"1\" class=\"a\">Text</p><p id=\"2\" class=\"a\">Text</p></div>";
    Document doc = Jsoup.parse(html);
    Elements els = doc.select("p");
    Element e0 = els.get(0);
    Element e1 = els.get(1);

    assertFalse(e0.equals(e1));
}
